use dep::poseidon::poseidon2::Poseidon2;
use std::field::bn254;

// keccak256("tornado") % BN254_FIELD_SIZE
global MERKLE_TREE_DEFAULT_ZERO: Field = 0x2fe54c60d3acabf3343a35b6eba15db4821b340f76e741e2249685ed4899af6c;

pub fn compute_merkle_root<let LEVELS: u32>(leaf: Field, path_elements: [Field; LEVELS], path_indices: Field) -> Field {
    let path_bits = path_indices.to_le_bits::<LEVELS>();

    let mut current_hash = leaf;

    for i in 0..LEVELS {
        let (left, right) = if path_bits[i] == 0 {
            (current_hash, path_elements[i])
        } else {
            (path_elements[i], current_hash)
        };
        current_hash = Poseidon2::hash::<2>([left, right], 2);
    }

    current_hash
}

pub fn compute_merkle_tree<let N_LEAVES: u32>(levels: u8, leaves: [Field; N_LEAVES]) -> Field {
    // Ensure that all leaves can be stored in the tree.
    assert(2 << levels - 1 >= N_LEAVES, "tree too small to process all leaves");

    // Track the current elements to hash (defaults to the passed-in leaves).
    let mut elems_to_hash = Vec::from_slice(leaves);

    // Iterate over every level, starting from the bottom.
    // For loop is equivalent to `for (level = levels; level > 0; level--)`.
    for level in 0..=(levels - 1) {
        // Track the elements to hash in the next round.
        // This vector will be filled with the hashes of the current round.
        let mut next_elems_to_hash = Vec::new();

        // Calculate number of elements per level as well as the number of pairs.
        let num_elems = 2 << levels - 1 - level;
        let num_pairs = num_elems / 2;

        // Iterate over every pair to hash.
        for i in 0..num_pairs {
            let left_idx = i * 2;
            let right_idx = (i * 2) + 1;

            // Identify the left element to hash (default to the zero value
            // if there's none).
            let left = if left_idx < elems_to_hash.len() {
                elems_to_hash.get(left_idx)
            } else {
                MERKLE_TREE_DEFAULT_ZERO
            };

            // Identify the right element to hash (default to the zero value
            // if there's none).
            let right = if right_idx < elems_to_hash.len() {
                elems_to_hash.get(right_idx)
            } else {
                MERKLE_TREE_DEFAULT_ZERO
            };

            // Compute hash of pair.
            let hash = Poseidon2::hash::<2>([left, right], 2);

            // Add the computed hash to the vector which tracks the elements
            // to hash in the next round.
            next_elems_to_hash.push(hash);
        }

        // Set the new elements to be hashed in the next round to the hashes
        // we've just computed in this round.
        elems_to_hash = next_elems_to_hash;
    }

    // Return the root of the tree which is the hash of the last two elements.
    elems_to_hash.get(0)
}

pub fn verify_exclusion_proofs<let N: u32, let LEVELS: u32>(
    root: Field,
    keys: [Field; N],
    leaf_keys: [Field; N],
    leaf_next_keys: [Field; N],
    path_elements: [[Field; LEVELS]; N],
    path_indices: [Field; N],
) {
    // remove the for loop
    for i in 0..N {
        bn254::assert_lt(leaf_keys[i], keys[i]);
        if leaf_next_keys[i] != 0 {
            bn254::assert_lt(keys[i], leaf_next_keys[i]);
        }

        let leaf_hash = Poseidon2::hash::<2>([leaf_keys[i], leaf_next_keys[i]], 2);
        let computed_root = compute_merkle_root::<LEVELS>(leaf_hash, path_elements[i], path_indices[i]);
        assert(computed_root == root);
    }
}

pub fn verify_inclusion_proof<let LEVELS: u32>(
    root: Field,
    key: Field,
    leaf_next_key: Field,
    path_elements: [Field; LEVELS],
    path_index: Field,
) {
    if leaf_next_key != 0 {
        bn254::assert_lt(key, leaf_next_key);
    }

    let leaf_hash = Poseidon2::hash::<2>([key, leaf_next_key], 2);
    let computed_root = compute_merkle_root::<LEVELS>(leaf_hash, path_elements, path_index);
    assert(computed_root == root);
}

#[test]
fn test_compute_merkle_tree_pass_1() {
    let levels = 5;
    let root = 0x1a3f2760c48ce20488041872caab9b32cf82dd974b4033febca4fe8f89ff7142;
    let leaves = [0x1, 0x2, 0x3, 0x4, 0x5, 0x6, 0x7, 0x8, 0x9, 0xa, 0xb, 0xc, 0xd, 0xe, 0xf, 0x10, 0x11, 0x12, 0x13, 0x14];

    let result = compute_merkle_tree(levels, leaves);

    assert_eq(result, root);
}

#[test]
fn test_compute_merkle_tree_pass_2() {
    let levels = 4;
    let root = 0x1528946361c480e8dc1e9ae3f8c31c997625fa1ddeddc7db5ad0dce3ac58fc4c;
    let leaves = [0x1, 0x2, 0x3, 0x4, 0x5, 0x6, 0x7, 0x8, 0x9, 0xa, 0xb, 0xc, 0xd, 0xe, 0xf, 0x10];

    let result = compute_merkle_tree(levels, leaves);

    assert_eq(result, root);
}

#[test(should_fail_with = "tree too small")]
fn test_compute_merkle_tree_fail_1() {
    let levels = 4;
