use dep::poseidon::poseidon2::Poseidon2;

// helper: a == b ? 1 : 0
pub fn is_equal(a: Field, b: Field) -> Field {
    Field::from(a == b)
}

/**
 * Computes a Poseidon2 hash of all given sub UTXOs deposit ids and amounts.
 *
 * @param sub_deposit_ids All deposit ids contained in a parent UTXO
 * @param sub_deposit_amounts The corresponding amounts, ordered by ids
 * @returns Sub UTXOs compound hash
 */
pub fn compute_subutxo_hash<let N_DEPOSIT_COMPONENTS: u32>(
    sub_deposit_ids: [Field; N_DEPOSIT_COMPONENTS],
    sub_deposit_amounts: [Field; N_DEPOSIT_COMPONENTS],
) -> Field {
    let mut data: [Field; N_DEPOSIT_COMPONENTS * 2] = [0; N_DEPOSIT_COMPONENTS * 2];
    for i in 0..N_DEPOSIT_COMPONENTS {
        data[i] = sub_deposit_ids[i];
        data[i + N_DEPOSIT_COMPONENTS] = sub_deposit_amounts[i];
    }
    Poseidon2::hash::<N_DEPOSIT_COMPONENTS * 2>(data, N_DEPOSIT_COMPONENTS * 2)
}

