use dep::poseidon::poseidon2::Poseidon2;
use dep::schnorr;
use dep::utils::{merkleproof, utils};
use std::embedded_curve_ops::EmbeddedCurvePoint;
use utils::{compute_subutxo_hash, is_equal};
mod test;

// Domain separator for spend-auth Schnorr challenge.
// message: "bermudabay:stx:spend-auth:schnorr:v1"
global SCHNORR_DOMAIN: Field = 18593004833411356993981768246051920231328811611081460266067910279816360120902;

pub fn circuit<let CHAIN_ID: u32, let LEVELS: u32, let INDEXED_LEVELS: u32, let N_INS: u32, let N_OUTS: u32, let N_DEPOSIT_COMPONENTS: u32, // The maximum number of sub-UTXO components a note can have.
let N_DEPOSIT_ID_SLOTS: u32 // The number of slots for the deposit_id handled by the stx-transaction.
>(
    root: Field, // pub
    // extAmount = external amount used for deposits and withdrawals
    // correct extAmount range is enforced on the smart contract
    // publicAmount = extAmount - fee
    public_amount: Field, // pub
    ext_data_hash: Field, // pub
    challenge: Field, // pub
    recipient: Field, // pub - external recipient binding for Safe withdrawals
    spending_limit: Field, // maximum value Safe authorizes to spend
    // sub-UTXO: private list of deposit_ids this stx-tx can operate on.
    deposit_id_slots: [Field; N_DEPOSIT_ID_SLOTS],
    // sub-UTXO: public per-deposit_id delta (sum equals public_amount).
    public_deposit_id_deltas: [Field; N_DEPOSIT_ID_SLOTS], // pub
    // exclusion indexed merkle tree's root and witnesses
    exclusion_root: Field, // pub
    exclusion_leaf_keys: [Field; N_DEPOSIT_ID_SLOTS],
    exclusion_leaf_next_keys: [Field; N_DEPOSIT_ID_SLOTS],
    exclusion_path_indices: [Field; N_DEPOSIT_ID_SLOTS],
    exclusion_path_elements: [[Field; INDEXED_LEVELS]; N_DEPOSIT_ID_SLOTS],
    // data for transaction inputs
    in_nullifier: [Field; N_INS], // pub
    in_safe: [Field; N_INS],
    in_amount: [Field; N_INS],
    in_pubkey_x: [Field; N_INS],
    in_pubkey_y: [Field; N_INS],
    // signature = [s.lo, s.hi, e.lo, e.hi]
    in_transaction_signature: [[Field; 4]; N_INS],
    in_nullifier_signature: [[Field; 4]; N_INS],
    in_blinding: [Field; N_INS],
    in_token: [Field; N_INS],
    in_note: [Field; N_INS],
    in_path_indices: [Field; N_INS],
    in_path_elements: [[Field; LEVELS]; N_INS],
    // sub-UTXO: per-input deposit_id allocation; amounts sum to in_amount[i].
    in_sub_deposit_ids: [[Field; N_DEPOSIT_COMPONENTS]; N_INS],
    in_sub_deposit_amounts: [[Field; N_DEPOSIT_COMPONENTS]; N_INS],
    // data for transaction outputs
    out_commitment: [Field; N_OUTS], // pub
    out_safe: [Field; N_OUTS],
    out_amount: [Field; N_OUTS],
    out_pubkey_hash: [Field; N_OUTS],
    out_blinding: [Field; N_OUTS],
    out_token: [Field; N_OUTS],
    out_note: [Field; N_OUTS],
    // sub-UTXO: per-output deposit_id breakdown; amounts sum to out_amount[i].
    out_sub_deposit_ids: [[Field; N_DEPOSIT_COMPONENTS]; N_OUTS],
    out_sub_deposit_amounts: [[Field; N_DEPOSIT_COMPONENTS]; N_OUTS],
) {
    // deposit_id slots must be unique.
    for a in 0..N_DEPOSIT_ID_SLOTS {
        for b in (a + 1)..N_DEPOSIT_ID_SLOTS {
            let a_nz: bool = deposit_id_slots[a] != 0;
            let b_nz: bool = deposit_id_slots[b] != 0;
            if a_nz & b_nz {
                assert(deposit_id_slots[a] != deposit_id_slots[b]);
            }
        }
    }
    let chain_id = CHAIN_ID as Field;
    // Aggregate all input nullifiers and output commitments into one field each.
    let inputs_nullifier_hash = Poseidon2::hash::<N_INS>(in_nullifier, N_INS);
    let outputs_commitment_hash = Poseidon2::hash::<N_OUTS>(out_commitment, N_OUTS);

    // Construct stx hash
    let stx_hash = Poseidon2::hash::<8>(
        [chain_id, root, public_amount, ext_data_hash, recipient, spending_limit, inputs_nullifier_hash, outputs_commitment_hash],
        8,
    );

    let mut in_pubkey_hashes: [Field; N_INS] = [0; N_INS];
    let mut sum_ins: Field = 0;
    // An array tracking cumulative deposits and withdrawals by deposit_id.
    let mut sum_in_by_deposit_id: [Field; N_DEPOSIT_ID_SLOTS] = [0; N_DEPOSIT_ID_SLOTS];
    let mut sum_out_by_deposit_id: [Field; N_DEPOSIT_ID_SLOTS] = [0; N_DEPOSIT_ID_SLOTS];

    // verify correctness of transaction inputs
    for i in 0..N_INS {
        let pubkey_point = EmbeddedCurvePoint { x: in_pubkey_x[i], y: in_pubkey_y[i], is_infinite: false };
        // Hash pubkey point to a single field for commitments.
        in_pubkey_hashes[i] = Poseidon2::hash::<2>([in_pubkey_x[i], in_pubkey_y[i]], 2);

        // Verify transaction signature.
        assert(
            schnorr::verify_signature(
                pubkey_point,
                in_transaction_signature[i],
                stx_hash,
                SCHNORR_DOMAIN,
            ),
        );

        let in_sub_hash = compute_subutxo_hash::<N_DEPOSIT_COMPONENTS>(in_sub_deposit_ids[i], in_sub_deposit_amounts[i]);
        let in_commitment_hash = Poseidon2::hash::<7>(
            [in_amount[i], in_pubkey_hashes[i], in_blinding[i], in_token[i], in_safe[i], in_note[i], in_sub_hash],
            7,
        );

        // Verify nullifier signature.
        let nullifier_message = Poseidon2::hash::<3>([in_commitment_hash, in_path_indices[i], chain_id], 3);
        assert(
            schnorr::verify_signature(
                pubkey_point,
                in_nullifier_signature[i],
                nullifier_message,
                SCHNORR_DOMAIN,
            ),
        );

        // Verify nullifier hash matches the public input.
        // e = e.lo + e.hi * 2^128 (signature = [s.lo, s.hi, e.lo, e.hi])
        let nullifier_signature_e_field = in_nullifier_signature[i][2] + in_nullifier_signature[i][3] * 0x100000000000000000000000000000000;
        let in_nullifier_hash = Poseidon2::hash::<3>(
            [in_commitment_hash, in_path_indices[i], nullifier_signature_e_field],
            3,
        );
        assert(in_nullifier_hash == in_nullifier[i]);

        // check merkle proof only if amount is non-zero
        if in_amount[i] != 0 {
            let merkle_root = merkleproof::compute_merkle_root(in_commitment_hash, in_path_elements[i], in_path_indices[i]);
            assert(merkle_root == root);
        }

        // Note internal conservation
        // For each Note, in_amount[i] equals the total sub-UTXO (the sum of in_sub_deposit_amounts[i][k]).
        let mut note_in_sum: Field = 0;
        for k in 0..N_DEPOSIT_COMPONENTS {
            in_sub_deposit_amounts[i][k].assert_max_bit_size::<248>();
            note_in_sum += in_sub_deposit_amounts[i][k];
        }
        assert(note_in_sum == in_amount[i]);
        // Each sub-UTXO belongs to exactly one deposit_id in deposit_id_slots,
        // and its amount is accumulated into sum_in_by_deposit_id for that deposit_id.
        for k in 0..N_DEPOSIT_COMPONENTS {
            let sub_amount = in_sub_deposit_amounts[i][k];
            let sub_deposit_id = in_sub_deposit_ids[i][k];
            if sub_amount != 0 {
                assert(sub_deposit_id != 0);
                let mut match_count: Field = 0;
                for t in 0..N_DEPOSIT_ID_SLOTS {
                    let matches_deposit_id = is_equal(sub_deposit_id, deposit_id_slots[t]);
                    match_count += matches_deposit_id;
                    sum_in_by_deposit_id[t] += sub_amount * matches_deposit_id;
                }
                assert(match_count == 1);
            }
        }
        // we don't need to range check input amounts, since all inputs are valid UTXOs that
        // were already checked as outputs in the previous transaction (or zero amount UTXOs that don't
        // need to be checked either).
        sum_ins += in_amount[i];
    }

    let mut sum_outs: Field = 0;

    // verify correctness of transaction outputs
    for i in 0..N_OUTS {
        let out_sub_hash = compute_subutxo_hash::<N_DEPOSIT_COMPONENTS>(out_sub_deposit_ids[i], out_sub_deposit_amounts[i]);
        let out_commitment_hash = Poseidon2::hash::<7>(
            [out_amount[i], out_pubkey_hash[i], out_blinding[i], out_token[i], out_safe[i], out_note[i], out_sub_hash],
            7,
        );
        assert(out_commitment_hash == out_commitment[i]);

        // check that amount fits into 248 bits to prevent overflow
        let _ = out_amount[i].to_le_bits::<248>();

        // Note internal conservation
        // For each Note, out_amount[i] equals the total sub-UTXO (the sum of out_sub_deposit_amounts[i][k]).
        let mut note_out_sum: Field = 0;
        for k in 0..N_DEPOSIT_COMPONENTS {
            out_sub_deposit_amounts[i][k].assert_max_bit_size::<248>();
            note_out_sum += out_sub_deposit_amounts[i][k];
        }
        assert(note_out_sum == out_amount[i]);
        // Each sub-UTXO belongs to exactly one deposit_id in deposit_id_slots,
        // and its amount is accumulated into sum_out_by_deposit_id for that deposit_id.
        for k in 0..N_DEPOSIT_COMPONENTS {
            let sub_amount = out_sub_deposit_amounts[i][k];
            let sub_deposit_id = out_sub_deposit_ids[i][k];
            if sub_amount != 0 {
                assert(sub_deposit_id != 0);
                let mut match_count: Field = 0;
                for t in 0..N_DEPOSIT_ID_SLOTS {
                    let matches_deposit_id = is_equal(sub_deposit_id, deposit_id_slots[t]);
                    match_count += matches_deposit_id;
                    sum_out_by_deposit_id[t] += sub_amount * matches_deposit_id;
                }
                assert(match_count == 1);
            }
        }

        sum_outs += out_amount[i];
    }

    // check that there are no same nullifiers among all inputs
    for i in 0..N_INS {
        for j in (i + 1)..N_INS {
            assert(in_nullifier[i] != in_nullifier[j]);
        }
    }

    // check the token consistency: all inputs share in_token[0]; all outputs must equal that token.
    for i in 0..N_INS {
        assert(in_token[i] == in_token[0]);
    }
    for j in 0..N_OUTS {
        assert(out_token[j] == in_token[0]);
    }

    // check Safe consistency: all input Safe values share in_safe[0]
    for i in 0..N_INS {
        assert(in_safe[i] == in_safe[0]);
    }

    // 4 every output
    // if the output's pubkey matches with one of the input's privkeys
    // assert that the output's safe is equal that input one's
    for i in 0..N_OUTS {
        for j in 0..N_INS {
            if out_pubkey_hash[i] == in_pubkey_hashes[j] {
                assert(out_safe[i] == in_safe[j]);
            }
        }
    }

    // 4. per-deposit_id conservation & public deltas
    let mut sum_public_deposits: Field = 0;
    for t in 0..N_DEPOSIT_ID_SLOTS {
        sum_public_deposits += public_deposit_id_deltas[t];
    }
    assert(sum_public_deposits == public_amount);
    for t in 0..N_DEPOSIT_ID_SLOTS {
        assert(sum_in_by_deposit_id[t] + public_deposit_id_deltas[t] == sum_out_by_deposit_id[t]);
    }
    for t in 0..N_DEPOSIT_ID_SLOTS {
        if public_deposit_id_deltas[t] != 0 {
            merkleproof::verify_exclusion_proofs::<1, INDEXED_LEVELS>(
                exclusion_root,
                [deposit_id_slots[t]],
                [exclusion_leaf_keys[t]],
                [exclusion_leaf_next_keys[t]],
                [exclusion_path_elements[t]],
                [exclusion_path_indices[t]],
            );
        }
    }

    // if it's a Safe transaction, then recompute stx hash and challenge hash
    // and verify that the recomputed challenge hash equals its public input
    // equivalent.
    if (in_safe[0] != 0) & (sum_ins != 0) {
        let safe = in_safe[0];

        let challenge_hash = Poseidon2::hash::<2>([safe, stx_hash], 2);
        assert(challenge_hash == challenge);

        // Enforce that the net value leaving the Safe does not exceed Safe spending_limit.
        spending_limit.assert_max_bit_size::<248>();
        let safe_to_external_amount = sum_ins - sum_outs;
        safe_to_external_amount.assert_max_bit_size::<248>();
        let remaining_spending_limit = spending_limit - safe_to_external_amount;
        remaining_spending_limit.assert_max_bit_size::<248>();
    }

    // verify amount invariant
    assert((sum_ins + public_amount) == sum_outs);

    // optional safety constraint to make sure extDataHash cannot be changed
    let _ = ext_data_hash * ext_data_hash;
}
